import{_ as i,r as a,o as n,c as s,b as t,d as e,e as l,a as o}from"./app-2a089349.js";const d={},h=o('<h1 id="how-to-access-the-stripe-customer-portal-from-the-website" tabindex="-1"><a class="header-anchor" href="#how-to-access-the-stripe-customer-portal-from-the-website" aria-hidden="true">#</a> How to Access the Stripe Customer Portal from the Website</h1><p>To Access the Stripe Customer Portal from the Website, do the following steps below:</p><h3 id="stripe-predefined-page-customer-portal" tabindex="-1"><a class="header-anchor" href="#stripe-predefined-page-customer-portal" aria-hidden="true">#</a> Stripe Predefined Page - Customer Portal</h3><p>In UM Stripe version 1.0.7, there&#39;s a newly added feature—the Stripe predefined page created specifically for the <strong>direct</strong> customer portal URL. (e.g.: yoursite.com/<strong>customer-porta</strong>l/) Upon logging in and accessing this page, you will seamlessly be redirected to the Stripe customer portal site.</p><p>The redirection feature is designed exclusively for users who are currently logged in. If the Stripe predefined page is added to the profile menu, it&#39;s important to note that <strong>logged-out users</strong> won&#39;t experience any redirection. Clicking on the menu will yield no results for them.</p><p>For users who are <strong>logged in</strong>, the experience differs slightly. Although they can click on the menu and initiate the redirection, they won&#39;t be able to view the predefined page as intended. Instead, they will be promptly redirected to the Stripe customer portal site.</p><p>Upon activating the extension, a notification in wp-admin will prompt you to create pages. By clicking the <strong>&quot;Create Pages&quot;</strong> button, the customer portal page is automatically generated. For existing Stripe customers upgrading to version 1.0.7, the notification to create pages will reappear. Clicking on it will initiate the generation of the customer portal page.</p><p>To customize the slug of this predefined page, navigate to <strong>UM &gt; Settings &gt; General &gt; Pages. Hover your cursor over &#39;Customer Portal — UM Customer Portal&gt; click the Quick Edit link</strong>. From there, you can modify the Slug as needed.</p><h3 id="account-billing-tab" tabindex="-1"><a class="header-anchor" href="#account-billing-tab" aria-hidden="true">#</a> Account Billing Tab</h3><p>When the UM Stripe extension is enabled, a new tab named &quot;Billing&quot; is automatically added to the user&#39;s account page.</p><ol><li>To access it on your site, go to <strong>User &gt; Account Settings &gt; Billing tab</strong>.</li><li>Here, you will find the <strong>Customer Portal button</strong>. The customer portal is a secure, Stripe-hosted page designed for managing your subscription and billing information.</li><li>Clicking the Customer Portal button will redirect you to the external page of the Stripe Customer Portal, providing you with the necessary tools to handle your subscriptions.</li></ol><h3 id="add-customer-portal-shortcode-to-a-page" tabindex="-1"><a class="header-anchor" href="#add-customer-portal-shortcode-to-a-page" aria-hidden="true">#</a> Add Customer Portal Shortcode to a Page</h3>',12),c={href:"https://ultimatemember.github.io/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference.html",target:"_blank",rel:"noopener noreferrer"},u=t("strong",null,"[ultimatemember_stripe_customer_portal]",-1),g=o('<h4 id="steps-in-adding-the-shortcode-to-a-page" tabindex="-1"><a class="header-anchor" href="#steps-in-adding-the-shortcode-to-a-page" aria-hidden="true">#</a> Steps in adding the shortcode to a page</h4><ol><li>Go to wp-admin&gt;Pages&gt;Add new page.</li><li>Add a title to your Page, e.g. &quot;Manage my billings&quot; and customize the page to your preference.</li><li>Add a shortcode block and paste the Customer Portal Shortcode: <code>[ultimatemember_stripe_customer_portal]</code></li><li>Publish the page.</li></ol><h4 id="steps-in-adding-the-page-to-the-profile-menu" tabindex="-1"><a class="header-anchor" href="#steps-in-adding-the-page-to-the-profile-menu" aria-hidden="true">#</a> Steps in adding the page to the profile menu</h4><ol><li>Go to wp-admin &gt; Appearance &gt; Menus.</li><li>In the &#39;<strong>Add Menu Items&#39;</strong> section, under the <strong>Pages,</strong> toggle dropdown, select the page you created by checking the checkboxes (e.g., &quot;Manage my billings&quot;)</li><li>Click the <strong>&#39;Add to Menu&#39;</strong> button. It will then be added to the menu structure.</li><li>In the menu structure, locate the button part and check the menu settings to determine where you want to add the page (e.g., Primary Menu).</li><li>Click the <strong>&#39;Save Menu&#39;</strong> button. Then check on your site if the menu has been successfully added.</li></ol><h4 id="customer-portal-button-on-your-website" tabindex="-1"><a class="header-anchor" href="#customer-portal-button-on-your-website" aria-hidden="true">#</a> Customer Portal Button on your Website</h4><ol><li>On your site, click on the menu you have added.</li><li>You&#39;ll see the button &quot;Manage Billing&quot;, click on the button to test.</li><li>It should <strong>redirect</strong> you to the external page of the Stripe Customer Portal to manage subscriptions.</li></ol>',6);function p(m,b){const r=a("ExternalLinkIcon");return n(),s("div",null,[h,t("p",null,[e("As outlined in this "),t("a",c,[e("article"),l(r)]),e(" , the customer portal shortcode generates a button, allowing customers to be redirected to the external page of the Stripe Customer Portal for seamless subscription management. Allow your customers with the ability to manage their subscription plans through the following Customer Portal Shortcode: "),u]),g])}const y=i(d,[["render",p],["__file","1894-how-to-access-the-stripe-customer-portal-from-the-website.html.vue"]]);export{y as default};
